#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0; 
    char buf[20];
    getchar(); // consume newline after T
    while(T--){
        if(!fgets(buf, sizeof(buf), stdin)) break;
        size_t len = strlen(buf);
        if(len && buf[len-1]=='\n') buf[--len]='\0';
        if(len!=5 || buf[2]!='-'){
            puts("Error");
            continue;
        }
        char c1=buf[0], r1=buf[1], c2=buf[3], r2=buf[4];
        if(c1<'a'||c1>'h'||c2<'a'||c2>'h'||r1<'1'||r1>'8'||r2<'1'||r2>'8'){
            puts("Error");
            continue;
        }
        int col1=c1-'a', col2=c2-'a';
        int row1=r1-'1', row2=r2-'1';
        int dx=abs(col2-col1), dy=abs(row2-row1);
        if((dx==1 && dy==2) || (dx==2 && dy==1)) puts("Yes");
        else puts("No");
    }
    return 0;
}

