import sys

def is_knight(c1,r1,c2,r2):
    dx=abs(ord(c2)-ord(c1))
    dy=abs(int(r2)-int(r1))
    return (dx==1 and dy==2) or (dx==2 and dy==1)

def solve():
    data=sys.stdin.read().splitlines()
    if not data: return
    T=int(data[0].strip())
    out=[]
    for i in range(1,T+1):
        s=data[i]
        if len(s)!=5 or s[2]!='-':
            out.append('Error')
            continue
        c1,r1,c2,r2=s[0],s[1],s[3],s[4]
        if not('a'<=c1<='h' and 'a'<=c2<='h' and '1'<=r1<='8' and '1'<=r2<='8'):
            out.append('Error')
            continue
        out.append('Yes' if is_knight(c1,r1,c2,r2) else 'No')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    solve()

